/*
 * sc_ui_atlas_origin.h — Origin Lux sprite atlas descriptor
 *
 * Atlas: sdcard/assets/themes/origin/atlas.bin
 * Format: RGB565, 512 × 512 pixels (524 288 bytes)
 * Generated by: tools/pack_sprite_atlas.py --theme origin
 *
 * Design language: smoked glass, brushed aluminium, anodised gold trim,
 * ice-blue data accent.  Rounded corners (4–6 px), soft inner glow,
 * generous negative space.  Contrast with Drake's rivets and hazard tape.
 *
 * ┌────────────────────────────────────────────────────────┐
 * │  Row 0   y=0    Buttons 7× (140×56 each)               │
 * │  Row 1   y=56   Slider tracks + thumb                  │
 * │  Row 2   y=112  Axes (120×120 Joystick/DPAD/HAAT)       │
 * │  Row 3   y=232  Throttle/Yaw/Rudder                    │
 * │  Row 4   y=312  Jog wheel frames (96×96 × 8)            │
 * │  Row 5   y=408  Knob ring + cap (64×64 each)            │
 * │  Row 6   y=472  9-slice panel pieces                   │
 * └────────────────────────────────────────────────────────┘
 *
 * Sprite grid mirrors the Drake layout so atlas coordinates stay symmetric
 * — only pixel content differs.  The packer enforces this with --same-grid.
 */
